INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "春咲 ひより", 0, 1, 1001, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1, 2, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1.4, 0, 0, "お！\nあそこに困ってそうな人発見！", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "草野 優衣", 0, 1, 1002, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1, 2, "みんなみたいに\nわたしも強くならなきゃ", 1.4, 0, 0, "大切な人を\n守れるようになりたい…って", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "士条 怜", 0, 1, 1003, "少しは磨かれると思いますよ。", 1, 2, "フェンシングを始めてみては？", 1.4, 0, 0, "キミに必要な集中力と感性が", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "穂高 みそぎ", 0, 1, 1004, "みそぎはねぇ、\nかくれんぼやりたい！", 1, 2, "ねぇ、にいちゃん！", 1.5, 0, 0, "今日はなにして遊ぶ？", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "風宮 あかり", 0, 1, 1006, "私といっしょに…\nいかない？", 1, 2, "風宮あかりです", 1.4, 0, 0, "ねぇ…", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "出雲 宮子", 0, 1, 1007, "食べ物の恨みは怖いのー", 1, 2, "出雲宮子なのー", 1.5, 0, 0, "プリンたべたいのー", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "虹村 雪", 0, 1, 1008, "いいよ。\n見られることは運命さ…", 1, 2, "ボクは虹村雪。", 1.4, 0, 0, "キミもボクの美貌に\n吸い寄せられたんだね。", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "柊杏奈", 0, 1, 1009, "人呼んで「疾風の冥姫」!!", 1, 2, "フッ…聞いて後悔するがいい！", 1.4, 0, 0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "姫宮 真歩", 0, 1, 1010, "ほんまおおきにやわ～♪", 1, 2, "マホマホ王国のプリンセス、\nまほ姫どす", 1.5, 0, 0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "衣之咲 璃乃", 0, 1, 1011, "ここで会ったが\n100年目～！", 1, 2, "衣之咲璃乃です！", 1.4, 0, 0, "生き別れたお兄ちゃんを探して\n三千世界！", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "柏崎 初音", 0, 1, 1012, "…って、お願い！\n誰にも言わないでおいて～！", 1, 2, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 1.4, 0, 0, "ち、超能力って…\n何のことかな～？", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "美波 鈴奈", 0, 1, 1016, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1, 2, "ちょす！\n美波鈴奈だよ～♪", 1.4, 0, 0, "一応カリスマ読モJKやってまっす！", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "喜屋武 香織", 0, 1, 1017, "でも、沖縄もとってもいいとこさー", 1, 2, "はいたーい。\n喜屋武香織さー。", 1.4, 0, 0, "東京は遊園地みたいなところさー", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "支倉 伊緒", 0, 1, 1018, "イオちゃんって呼んでね。", 1, 2, "支倉伊緒です。", 1.4, 0, 0, "先生って呼ばれるのは\nくすぐったいから", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "茜 ミミ", 0, 1, 1020, "ミミをおいてかないでぇ～", 1, 2, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1.5, 0, 0, "あ！/\お兄ちゃ～ん\nまってよ～", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "栗林 くるみ", 0, 1, 1021, "ふぇぇぇぇぇん……", 1, 2, "あ…あの…えっと…\n栗…林…くるみ…です……", 1.5, 0, 0, "あの……\nふぇ……", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "風宮 より", 0, 1, 1022, "なんてありがとうございます！", 1, 2, "風宮よりです。\nあああああ！", 1.4, 0, 0, "こんな私に貴重な時間を\n割いていただき、", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "北条 綾音", 0, 1, 1023, "私こっち行きたいー\nね、早く早くー", 1, 2, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1.5, 0, 0, "おにいちゃんどこいくの？\nえ？", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "天野 すずめ", 0, 1, 1025, "これて何か違う…\nあああすみません！", 1, 2, "わっ…わっ…私、\n天野すずめといいます！", 1.4, 0, 0, "ふ、不束者ですが\nどうぞ末永く…って、", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "倉石 恵理子", 0, 1, 1027, "離しませんわ………\n絶対に…!!", 1, 2, "……クスクス…私は\n…倉石恵理子……", 1.4, 0, 0, "あなたは…運命の……\n伴侶……", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "佐々木 咲恋", 0, 1, 1028, "…そうでしょ？？", 1, 2, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1.4, 0, 0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "桜井 望", 0, 1, 1029, "あはは、\n私もまだまだだなぁ～", 1, 2, "桜井望だよ！\nよろしくねっ", 1.4, 0, 0, "ぇっと…\nキミ、私のこと知らないの?!", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ニノン・ジュベール", 0, 1, 1030, "ショーグン、\nワタシと一緒に天下統一デース！", 1, 2, "デケデケデンっ！", 1.4, 0, 0, "初めまして、\n私はニノン・ジュベール申すデス！", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "上喜 しのぶ", 0, 1, 1031, "おかしいですね……", 1, 2, "上喜しのぶです。\n手元のドクロが父です。", 1.4, 0, 0, "でもって私の隣にいるのが……\nえ、見えない？", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "野戸まひる", 0, 1, 1033, "そう、\nオラのボケに突っ込める相方が…！", 1, 2, "目指すはビッグな\nお笑い芸人だっぺ！", 1.5, 0, 0, "けんども\nそれには足りないモンが…", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "綾瀬 ゆかり", 0, 1, 1034, "ちょ\nちょっと一杯飲んできます…！", 1, 2, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1.4, 0, 0, "ちょっと緊張しちゃって…", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "氷川 鏡華", 0, 1, 1036, "これ以上お話しすることは…\nないです！", 1, 2, "氷川鏡華…です", 1.5, 0, 0, "知らない人とは話しちゃいけないので", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "柏崎 栞", 0, 1, 1038, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1, 2, "柏崎…栞です。", 1.4, 0, 0, "……あ、アラーム。", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "双葉 碧", 0, 1, 1040, "野に咲く花が、\n唯一の話相手です。", 1, 2, "ふ、双葉碧です。", 1.4, 0, 0, "私、一人も友達がいなくて……", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "三角 千歌", 0, 1, 1042, "そう思っています。", 1, 2, "三角千歌です。", 1.4, 0, 0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "安芸 真琴", 0, 1, 1043, "う、疑ってすまなかったな…", 1, 2, "安芸真琴だ。", 1.4, 0, 0, "あぁ？\nお前のそいつの仲間か？", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "イリヤ・オーンスタイン", 0, 1, 1044, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1, 2, "わらわこそは夜を総べる者！", 1.4, 0, 0, "生けとし生ける全ての者よ！", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "遠見 空花", 0, 1, 1045, "ｌク、クウカに何かご用ですか!?", 1, 2, "そこで騎士は妖精を乱暴に……", 1.4, 0, 0, "ぐふふふふ……はっ！", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "宮坂たまき", 0, 1, 1046, "う～ん…\n猫ってホントに最高にゃ～♪", 1, 2, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 1.4, 0, 0, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "大神 美冬", 0, 1, 1048, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1, 2, "大神美冬よ！", 1.4, 0, 0, "それでは早速クエストに…", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "星野静流", 0, 1, 1049, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1, 2, "星野静流だよ！", 1.4, 0, 0, "クエストもバトルも\n掃除も洗濯も", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "玉泉美咲", 0, 1, 1050, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1, 2, "アタシは玉泉美咲。", 1.5, 0, 0, "見ての通りの\nセクシー美少女で", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "リマ", 0, 1, 1052, "？？？？", 1, 2, "？？？", 1.4, 0, 0, "？？？？", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "モニカ・ヴァイスヴィント", 0, 1, 1053, "そ、そこまでいうなら\nもらってやる", 1, 2, "モニカ・ヴァイスヴィントだ。", 1.5, 0, 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ペコリーヌ", 0, 1, 1058, "そ、そこまでいうなら\nもらってやる", 1, 2, "モニカ・ヴァイスヴィントだ。", 1.5, 0, 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "コッコロ", 0, 1, 1059, "そ、そこまでいうなら\nもらってやる", 1, 2, "モニカ・ヴァイスヴィントだ。", 1.5, 0, 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "キャル", 0, 1, 1060, "そ、そこまでいうなら\nもらってやる", 1, 2, "モニカ・ヴァイスヴィントだ。", 1.5, 0, 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1);
